def get_percept(guess, secret):
    if guess < secret:
        return 'too_low'
    elif guess > secret:
        return 'too_high'
    else:
        return 'correct'

def guessing_agent(low, high):
    return (low + high) // 2

secret = 73
low, high = 1, 100
percept = None
step = 1

while percept != 'correct':
    guess = guessing_agent(low, high)
    percept = get_percept(guess, secret)
    print(f"Step {step}: Guessed {guess} -> {percept}")
    if percept == 'too_low':
        low = guess + 1
    elif percept == 'too_high':
        high = guess - 1
    step += 1

print(f"Found {secret} in {step - 1} guesses!")
